import { Component, OnDestroy, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Subscription } from 'rxjs';
import { Match, Message } from '../../core/models';
import { MatchService } from '../../core/services/match.service';
import { SocketService } from '../../core/services/socket.service';

// Placeholder partner so the template can render before /matches resolves.
const EMPTY_PARTNER: Match = {
  id: '',
  user: { id: '', name: '', jobTitle: '', employer: '', bio: '', pictureUrl: '', photos: [], distanceKm: 0, mutualConnections: 0 },
  lastMessage: '',
  lastMessageAt: '',
  unread: 0,
};

@Component({
  selector: 'app-conversation',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './conversation.component.html',
  styleUrl: './conversation.component.css',
})
export class ConversationComponent implements OnInit, OnDestroy {
  private route = inject(ActivatedRoute);
  private matchService = inject(MatchService);
  private socket = inject(SocketService);

  readonly matchId = this.route.snapshot.paramMap.get('matchId') ?? '';

  readonly partners = signal<Match[]>([]);
  readonly messages = signal<Message[]>([]);
  readonly draft = signal('');

  readonly partner = computed(() => this.partners().find((p) => p.id === this.matchId) ?? EMPTY_PARTNER);
  readonly thread = computed(() => this.messages());

  private sub?: Subscription;

  ngOnInit(): void {
    if (this.matchId) {
      this.matchService.messages(this.matchId).subscribe({
        next: (msgs) => this.messages.set(msgs ?? []),
        error: () => this.messages.set([]),
      });
    }

    // Partner header derives from the matches list.
    this.matchService.list().subscribe({
      next: (matches) => this.partners.set((matches ?? []).filter((m) => !!m.user)),
      error: () => this.partners.set([]),
    });

    // Live inbound messages for this thread (dedupe against our own echo by id).
    this.sub = this.socket.messages$.subscribe((evt) => {
      if (!evt || evt.matchId !== this.matchId || !evt.id) return;
      this.messages.update((list) => {
        if (list.some((m) => m.id === evt.id)) return list;
        return [
          ...list,
          {
            id: evt.id!,
            matchId: this.matchId,
            senderId: evt.senderId ?? '',
            body: evt.body ?? '',
            createdAt: evt.createdAt ?? '',
            mine: false,
          },
        ];
      });
    });
  }

  ngOnDestroy(): void {
    this.sub?.unsubscribe();
  }

  send(): void {
    const body = this.draft().trim();
    if (!body || !this.matchId) return;
    this.matchService.send(this.matchId, body).subscribe({
      next: (msg) => {
        // Response has mine:true; dedupe in case the socket echoed it too.
        this.messages.update((list) =>
          list.some((m) => m.id === msg.id) ? list : [...list, msg],
        );
      },
      error: () => {},
    });
    this.draft.set('');
  }
}
